import styles from "./Popup.module.scss";
import React, { PureComponent } from "react";
import classNames from "classnames";
import PropTypes from "prop-types";
import { Classes } from "../../../../../common/constants/classes";
import { getBounds } from "../../../../utils/bounds";

export { styles as popupStyles };
export default class Popup extends PureComponent {
  static popupOffset = 5;

  static propTypes = {
    activityId: PropTypes.number
  };

  state = {
    show: false,
    top: 0,
    left: 0,
    title: "",
    content: ""
  };

  update(state = {}, container) {
    const { show, title, content, pos } = state;

    this.setState({ show, title, content }, () => this.updatePosition(pos, container));
  }

  updatePosition(position, container) {
    const { popup } = this.refs;

    if (this.state.show && popup && position) {
      const popupBB = getBounds(popup);
      const containerBB = getBounds(container);

      const popupHeight = popupBB.height + Popup.popupOffset;
      const popupWidth = popupBB.width + Popup.popupOffset;
      const popupBottom = position.top + popupHeight;
      const popupRight = position.left + popupWidth;

      this.setState({
        top:
          (containerBB.bottom < popupBottom
            ? position.top - (popupBottom - containerBB.bottom)
            : position.top + Popup.popupOffset) - containerBB.top,
        left:
          (containerBB.right < popupRight
            ? position.left - popupWidth
            : position.left + Popup.popupOffset) - containerBB.left
      });
    }
  }

  focusPopup() {
    this.refs.popup.focus();
  }

  get show() {
    return this.state.show;
  }

  render() {
    const { activityId = 0, focusCurrentSpot, focusNextSpot, popUpLeave } = this.props;
    const { title, content, top, left, show } = this.state;
    const tabIndex = {
      tabIndex: show ? "0" : "-1"
    };

    return (
      <div ref="popupContainer">
        <div
          {...tabIndex}
          className="focusCatcher1"
          ref="focusCatcher1"
          onFocus={focusCurrentSpot}
        />
        <div
          id={`${styles.container}-${activityId}`}
          className={classNames(styles.container, !show && Classes.VISUALLY_HIDDEN)}
          style={{ top, left }}
          aria-live="polite"
          role="status"
          ref="popup"
          onMouseLeave={popUpLeave}
          {...tabIndex}
        >
          {title && <div className={styles.title}>{title}</div>}
          <div className={styles.content} dangerouslySetInnerHTML={{ __html: content }} />
        </div>
        <div {...tabIndex} className="focusCatcher2" ref="focusCatcher2" onFocus={focusNextSpot} />
      </div>
    );
  }
}
