import styles from "./ActivityHeader.module.scss";
import React, { PureComponent } from "react";
import PropTypes from "prop-types";

export default class ActivityHeader extends PureComponent {
  static propTypes = {
    activityName: PropTypes.string.isRequired,
    studentInstruction: PropTypes.string.isRequired
  };

  render() {
    const { activityName, studentInstruction } = this.props;

    return (
      <div className={styles.container}>
        <h1 className={styles.name}>{activityName}</h1>
        <p className={styles.instruction}>{studentInstruction}</p>
      </div>
    );
  }
}
