import React, { memo } from "react";
import PropTypes from "prop-types";
import SvgElement from "../SvgElement/SvgElement";

const SvgImage = ({ url, viewBox }) => (
  <image {...viewBox} xmlnsXlink={SvgElement.xLink} xlinkHref={url} />
);

SvgImage.propTypes = {
  url: PropTypes.string.isRequired,
  viewBox: PropTypes.object.isRequired
};

export default memo(SvgImage);
