/* eslint jsx-a11y/anchor-is-valid:off */
import styles from "./BaseSpot.module.scss";
import React, { PureComponent } from "react";
import classNames from "classnames";
import PropTypes from "prop-types";
import { popupStyles } from "../Popup/Popup";
import { Key } from "../../../../../common/constants/keyboard";
import { getClientPosition } from "../../../../../common/utils/event";
import { getBounds } from "../../../../utils/bounds";
import SvgElement from "../SvgElement/SvgElement";
import { Classes } from "../../../../../common/constants/classes";
import { isMobile } from "../../../../../common/constants/user-agent";

export default class BaseSpot extends PureComponent {
  static propTypes = {
    activityId: PropTypes.number.isRequired,
    id: PropTypes.number.isRequired,
    mode: PropTypes.string.isRequired,
    title: PropTypes.string.isRequired,
    description: PropTypes.string.isRequired,
    complete: PropTypes.bool,
    visible: PropTypes.bool,
    regions: PropTypes.array.isRequired,
    color: PropTypes.string.isRequired,
    hitHandler: PropTypes.func,
    updateHandler: PropTypes.func
  };

  state = {
    visible: false,
    popUpShown: false
  };

  enterLeaveHandlers = {};
  clickPressHandlers = {};
  focusBlurHandlers = {};
  ariaLabel = "";
  ariaControls = "";
  ariaDescribedBy = "";

  constructor(props) {
    super(props);

    if (props.mode === "quiz") {
      this.ariaLabel = props.description;
      this.ariaControls = "";

      this.enterLeaveHandlers = {
        onMouseEnter: this.onQuizMouseEnter,
        onMouseLeave: this.onQuizMouseLeave
      };

      this.clickPressHandlers = {
        onMouseDown: this.onQuizMouseDown,
        onKeyDown: this.onQuizKeyDown
      };

      this.focusBlurHandlers = {
        onFocus: this.onQuizFocus,
        onBlur: this.onQuizBlur
      };
    } else {
      this.ariaLabel = "";
      this.ariaControls = `${popupStyles.container}-${props.activityId}`;

      this.enterLeaveHandlers = {
        onMouseEnter: this.onExploreMouseEnter,
        onMouseLeave: !isMobile ? this.onExploreMouseLeave : null,
        onMouseMove: this.onExploreMouseMove
      };

      this.clickPressHandlers = {
        onMouseDown: this.onExploreMouseDown,
        onKeyDown: this.onExploreKeyDown,
        onTouchEnd: this.onExploreTouchEnd
      };

      this.focusBlurHandlers = {
        onFocus: this.onExploreFocus,
        onBlur: props.togglePopup ? null : this.onExploreBlur
      };
    }

    this.ariaDescribedBy = this.ariaControls;
  }

  componentDidUpdate(prevProps) {
    if (prevProps.complete && !this.props.complete) {
      this.blurSpot();
    }
  }

  onClick = e => {
    e.preventDefault();
  };

  onQuizMouseDown = e => {
    e.preventDefault();
    e.stopPropagation();

    this.props.hitHandler({ id: this.props.id });
  };

  onExploreMouseDown = e => {
    const { togglePopup, spotSelected, spotNumber } = this.props,
      { popUpShown } = this.state;

    e.preventDefault();
    e.stopPropagation();

    if (togglePopup) {
      spotSelected(spotNumber);
      this.setState({
        popUpShown: !popUpShown
      });
    }
  };

  onExploreTouchEnd = e => {
    e.stopPropagation();
  };

  onQuizKeyDown = e => {
    if (e.keyCode === Key.ENTER || e.keyCode === Key.SPACEBAR) {
      e.preventDefault();
      this.props.hitHandler({ id: this.props.id });
    }
  };

  onExploreKeyDown = e => {
    const { togglePopup, spotNumber, focusPopup } = this.props;
    const { popUpShown } = this.state;

    if (e.keyCode === Key.ESC) {
      this.props.updateHandler({ show: false });
    } else if (e.keyCode === Key.ENTER || e.keyCode === Key.SPACEBAR) {
      if (togglePopup) {
        e.preventDefault();
        this.setState({
          popUpShown: !this.state.popUpShown
        });
      }
    } else if (e.keyCode === Key.TAB) {
      if (e.shiftKey) {
        this.onExploreBlur();
      } else {
        if (togglePopup && popUpShown) {
          e.preventDefault();
          focusPopup(spotNumber);
        } else {
          this.onExploreBlur();
        }
      }
    }
  };

  onQuizMouseEnter = () => {
    if (this.props.visible) {
      this.props.updateHandler(this.props.title);
    }
  };

  onQuizMouseLeave = () => {
    if (this.props.visible) {
      this.props.updateHandler("");
    }
  };

  onExploreMouseMove = e => {
    const { togglePopup } = this.props,
      { popUpShown } = this.state;

    if (togglePopup && popUpShown) {
      return;
    } else {
      this.onExploreMouseEnter(e);
    }
  };

  onExploreMouseEnter = e => {
    const { togglePopup } = this.props,
      { popUpShown } = this.state;
    if (togglePopup && popUpShown) {
      return;
    }

    const { x: left, y: top } = getClientPosition(e);

    this.props.updateHandler({
      show: true,
      pos: {
        top,
        left
      },
      title: this.props.title,
      content: this.props.description
    });
  };

  onExploreMouseLeave = () => {
    const { togglePopup } = this.props,
      { popUpShown } = this.state;

    if (togglePopup && popUpShown) {
      return;
    }
    this.props.updateHandler({ show: false });
  };

  onQuizFocus = () => {
    this.focusSpot();
  };

  onExploreFocus = e => {
    const { left, top, height, width } = getBounds(e.currentTarget);

    this.props.updateHandler({
      show: true,
      pos: {
        top: top + height / 2,
        left: left + width / 2
      },
      title: this.props.title,
      content: this.props.description
    });
    this.focusSpot();
  };

  onQuizBlur = () => {
    this.blurSpot();
  };

  onExploreBlur = () => {
    this.props.updateHandler({ show: false });
    this.blurSpot();
  };

  focusSpot() {
    this.setState({
      visible: true
    });
  }

  blurSpot() {
    this.setState({
      visible: false,
      popUpShown: false
    });
  }

  setFocus() {
    this.refs.linkRef.focus();
  }

  render() {
    return (
      <a
        ref="linkRef"
        href="#"
        className={classNames(
          styles.container,
          !this.state.visible && !this.props.visible && Classes.OPACITY
        )}
        id={this.props.id}
        role="button"
        aria-controls={this.ariaControls}
        aria-label={this.ariaLabel}
        aria-describedby={this.ariaDescribedBy}
        onClick={this.onClick}
        {...this.clickPressHandlers}
        {...this.enterLeaveHandlers}
        {...this.focusBlurHandlers}
        xmlnsXlink={SvgElement.xLink}
        xlinkHref="#"
      >
        {this.props.regions.map((item, key) => (
          <path key={key} stroke={this.props.color} fill="transparent" d={item.path} />
        ))}
      </a>
    );
  }
}
