import styles from "./SvgElement.module.scss";
import React, { PureComponent } from "react";
import PropTypes from "prop-types";
import classNames from "classnames";

export default class SvgElement extends PureComponent {
  static ns = "http://www.w3.org/2000/svg";
  static xLink = "http://www.w3.org/2000/svg";

  static defaultProps = {
    maxWidth: "100%",
    maxHeight: "100%",
    width: "auto",
    height: "auto"
  };

  static propTypes = {
    viewBox: PropTypes.object.isRequired,
    className: PropTypes.string,
    maxWidth: PropTypes.oneOfType([PropTypes.number, PropTypes.string]),
    maxHeight: PropTypes.oneOfType([PropTypes.number, PropTypes.string]),
    width: PropTypes.oneOfType([PropTypes.number, PropTypes.string]),
    height: PropTypes.oneOfType([PropTypes.number, PropTypes.string]),
    onMouseDown: PropTypes.func
  };

  onMouseDown = e => {
    if (this.props.onMouseDown) {
      e.preventDefault();
      this.props.onMouseDown();
    }
  };

  render() {
    return (
      <svg
        focusable="false"
        className={classNames(styles.container, this.props.className)}
        style={{
          maxWidth: this.props.maxWidth,
          maxHeight: this.props.maxHeight,
          width: this.props.width,
          height: this.props.height
        }}
        xmlns={SvgElement.ns}
        xmlnsXlink={SvgElement.xLink}
        xmlSpace="preserve"
        onMouseDown={this.onMouseDown}
        viewBox={`${this.props.viewBox.x} ${this.props.viewBox.y} ${this.props.viewBox.width} ${
          this.props.viewBox.height
        }`}
      >
        {this.props.children}
      </svg>
    );
  }
}
